// HasSalesOrder applies the HasEdge predicate on the "sales_order" edge.
func HasSalesOrder() predicate.Shipment {
	return predicate.Shipment(func(s *sql.Selector) {
		step := sqlgraph.NewStep(
			sqlgraph.From(Table, FieldID),
			sqlgraph.Edge(sqlgraph.M2O, true, SalesOrderTable, SalesOrderColumn),
		)
		sqlgraph.HasNeighbors(s, step)
	})
}

// HasSalesOrderWith applies the HasEdge predicate on the "sales_order" edge with a given conditions (other predicates).
func HasSalesOrderWith(preds ...predicate.SalesOrder) predicate.Shipment {
	return predicate.Shipment(func(s *sql.Selector) {
		step := newSalesOrderStep()
		sqlgraph.HasNeighborsWith(s, step, func(s *sql.Selector) {
			for _, p := range preds {
				p(s)
			}
		})
	})
}

